#:property AllowUnsafeBlocks=true

Console.WriteLine($"nint size: {nint.Size} bytes");

// stackalloc a Span<nint>
Span<nint> nints = stackalloc nint[5];
for (int i = 0; i < nints.Length; i++)
    nints[i] = i * 10;

Console.WriteLine("Span<nint> values:");
foreach (var val in nints)
    Console.Write($"  {val}");
Console.WriteLine();

// stackalloc a Span<nuint>
Span<nuint> nuints = stackalloc nuint[3];
nuints[0] = 100;
nuints[1] = 200;
nuints[2] = 300;

Console.WriteLine("Span<nuint> values:");
foreach (var val in nuints)
    Console.Write($"  {val}");
Console.WriteLine();

